    <section>
        <tg-list ref="tglistuser" :IsShowAction="true" :showCheckBox="true" :listType="['List']" ModuleName="Company"
            SubModuleCode="CMP_USER" IdentityColumn="user_id" HeaderText="Manage Device" :ListData="devices"
            :HeaderData="Headers" :ViewList="ViewList" v-on:ApplyView="OnApplyView"
            v-on:RefreshManageView="FetchUserData" :callbackfunction="FetchUserData" :HeaderButtons="listheaderbuttons"
            :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" :RenderRowActionMethod="renderActions"
            :IsFilterApplied="searchCondition ? true : false" :ListDataCallBackFunction="FetchUserData"
            :LegendArray="LegendArray" :SortExp="sortExp" :SortBy="sortBy" :NorecordfoundText="$t('NoRecordfound')"
            v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata" :widgets="widgets">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME === 'online'">
                    <div class="status-indicator" :class="data.row.online ? 'status-active' : 'status-inactive'"></div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'status'">
                    <listing-status :isfor="'USER'" ref="updatestatus" v-bind:dataid="data.row.status" Missing required
                        prop: module="Company" subModule="CannedReply" data-controller="compnay"
                        v-bind:statuslist="StatusListForListing" v-bind:item="data.status" data-action="index"
                        v-bind:dataselected="data.row.status == 1001 ? 'Active' : 'Inactive'"
                        v-bind:isselectedvaluestring="true"
                        v-bind:title="data.row.status == 1001 ? 'Active' : 'Inactive'" @change="FetchRecords(data.row)">
                    </listing-status>

                </template>
            </template>
        </tg-list>
        <DeviceDetailView v-if="deviceDetailShow" @close="deviceDetailShow = false" />
    </section>
</template>

