                DISPLAY_NAME: "Last Sync",
                DISPLAY_ORDER: 5,
            },
            {
                COLUMN_NAME: "status",
                DATA_TYPE: "text",
                SORTABLE: false,
                VISIBLE: true,
                DISPLAY_NAME: "Status",
                DISPLAY_ORDER: 6,
                settings: { isInSlot: true },
            },
        ];
        this.devices = [
            {
                id: 1,
                name: "Main Entrance Kiosk",
                deviceId: "KIOSK-001",
                model: "Samsung Tab A7",
                location: "Main Entrance",
                status: 1001,
                lastSync: "2023-10-15T14:30:00",
                faceAuthUrl: "http://192.168.1.101:5000/face-auth",
                syncFrequency: 15,
            },
            {
                id: 2,
                name: "Customer Service Kiosk",
                deviceId: "KIOSK-002",
                model: "iPad Pro 11",
                location: "Customer Service Desk",
                status: 1001,
                lastSync: "2023-10-15T13:45:00",
                faceAuthUrl: "http://192.168.1.102:8080/auth",
                syncFrequency: 10,
            },
            {
                id: 3,
                name: "Checkout Kiosk #1",
                deviceId: "KIOSK-003",
                model: "Android Tablet",
                location: "Checkout Area",
                status: 1002,
                lastSync: "2023-10-14T09:20:00",
                faceAuthUrl: "http://192.168.1.103:3000/face",
                syncFrequency: 30,
            },
            {
                id: 4,
                name: "Information Kiosk",
                deviceId: "KIOSK-004",
                model: "Samsung Tab S6",
                location: "Lobby Center",
                status: 1001,
                lastSync: "2023-10-15T14:15:00",
                faceAuthUrl: "http://192.168.1.104:5001/auth-service",
                syncFrequency: 20,
            },
            {
                id: 5,
                name: "Warehouse Kiosk",
                deviceId: "KIOSK-005",
                model: "iPad Air",
                location: "Warehouse Entrance",
                status: 1001,
                lastSync: "2023-10-15T13:10:00",
                faceAuthUrl: "http://192.168.1.105:4000/face-auth",
                syncFrequency: 60,
            },
            {
                id: 6,
                name: "Security Desk Kiosk",
                deviceId: "KIOSK-006",
                model: "Android Tablet",
                location: "Security Office",
                status: 1001,
                lastSync: "2023-10-15T12:30:00",
                faceAuthUrl: "http://192.168.1.106:6000/face",
                syncFrequency: 25,
            },
            {
                id: 7,
                name: "Training Room Kiosk",
                deviceId: "KIOSK-007",
                model: "Samsung Tab A8",
                location: "Training Room",
                status: 1002,
                lastSync: "2023-10-13T16:10:00",
                faceAuthUrl: "http://192.168.1.107:7000/auth",
                syncFrequency: 45,
            },
            {
                id: 8,
                name: "Reception Kiosk",
                deviceId: "KIOSK-008",
                model: "iPad 9th Gen",
                location: "Reception Area",
                status: 1001,
                lastSync: "2023-10-15T14:05:00",
                faceAuthUrl: "http://192.168.1.108:8000/face-auth",
                syncFrequency: 15,
            },
        ];
    },
    computed: {
        deviceList() {
            return this.devices.filter((d) => d.status === 1001);
        },
        totalDevices() {
            return this.devices.length;
        },

        activeDevices() {
            return this.devices.filter((d) => d.status === 1001).length;
        },

        inactiveDevices() {
            return this.devices.filter((d) => d.status === 1002).length;
        },

        avgSyncInterval() {
            if (!this.devices.length) return 0;

            const total = this.devices.reduce((sum, d) => sum + (d.syncFrequency || 0), 0);

            return Math.round(total / this.devices.length) + 'M';
        },
    },
    mounted() {
        this.startOfflineChecker();
        this.offlineDevice();
        this.FetchUserData();
    },
    watch: {
        devices: {
            deep: true,
            immediate: true,
            handler() {
                this.widgets = this.widgets.map((widget) => {
                    switch (widget.name) {
                        case "Total Devices":
                            return { ...widget, value: this.totalDevices };

                        case "Active Devices":
                            return { ...widget, value: this.activeDevices };

                        case "Inactive Devices":
                            return { ...widget, value: this.inactiveDevices };

                        case "Avg. Sync Interval":
                            return { ...widget, value: this.avgSyncInterval };

                        default:
                            return widget;
                    }
                });
            },
        },
    },
    beforeDestroy() {
        clearInterval(this.offlineTimer);
    },

    methods: {
        async FetchUserData() {
            const result = await DataService.DeviceList(`companyId=${this.GetUserInfo.CompanyId}`);
            console.log("FetchUserData", result)
        },
        FetchRecords(event) {
            //console.log("test",event);
            event.status = event.status == 1001 ? 1002 : 1001

        },
        startOfflineChecker() {
            this.offlineTimer = setInterval(() => {
                if (!this.lastOnlinePing) return;

                const diff = Date.now() - this.lastOnlinePing;

                // 30 seconds timeout
                if (diff > 30000) {


                    this.showOnlineDevice({ deviceId: "KIOSK-001" });
                    setTimeout(() => {
                        //this.offlineDevice();
                        this.showOnlineDevice({ deviceId: "KIOSK-001" });
                        this.showOnlineDevice({ deviceId: "KIOSK-005" });
                    }, 4000)
                }
            }, 5000); // check every 5 seconds
        },
        offlineDevice() {
            this.offlineTimer = setInterval(() => {
                const now = Date.now();

                this.devices = this.devices.map(device => {
                    if (!device.lastPing) return device;

                    const diff = now - device.lastPing;

                    // 30 sec timeout
                    if (diff > 30000) {
                        return {
                            ...device,
                            online: false
                        };
                    }

                    return device;
                });
            }, 5000);
        },
        showOnlineDevice(data) {
            const now = Date.now();

            this.devices = this.devices.map(device => {
                if (device.deviceId === data.deviceId) {
                    return {
                        ...device,
                        online: true,
                        lastPing: now
                    };
                }
                return device;
            });
        },
        commonHeaderButtonClick(event) {
            switch (event.callbackfunction) {
                case "removeFilter":
                    //ths.FetchUserData();
                    break;
            }
        },
        pagerMethod: function () {

        },
        leftCommonSearch: function () {

        },
        OnApplyView: function () {

        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.sortBy = s;
            if (s === this.sortBy) {
                if (this.sortExp == "") {
                    this.sortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                } else if (this.sortExp == "ASC") {
                    this.sortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                } else {
                    this.sortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            //this.FetchUserData();
            //$("#" + s + "  span:first-child").attr("class", SortDir);
        },
        actionButtonClick: function (callbackfunction, item, index, event) {
            console.log("checkk", callbackfunction);
            var vm = this;
            switch (callbackfunction) {
                case "ViewUserDetails":
                    this.deviceDetailShow = true;
                    break;
                case "sync":
                    this.AssignManager();
                    break;
                case "remoteLog":
                    //this.ManageView();
                    break;
                case "DefaultProject":
                    // vm.DefaultProduct(item);
                    break;
            }
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach((actionItem) => {
                let action = { ...actionItem };
                switch (action.title) {
                    case "View":
                        action.isVisible = true;
                        break;

                    default:
                        action.isVisible = true;
                        break;
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
    },
};
